{
  "hooks": {},
  "statusline": {
    "enabled": false
  }
}
EOF
echo "Test workspace created"

cd /tmp/test-workspace && timeout 10 claude -p --model haiku --setting-sources project <<'EOF'
Return a simple JSON object with a test field. Just output the JSON directly.

{
  "test": "value"
}
EOF

